#include <vector>

#include <cuda_runtime.h>

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

#define N 2048
#define IDX(i, j) ((i) + (j) * N)

static inline void cuda_check(cudaError_t err, const char* file, int line) {
  if (err != cudaSuccess) {
    std::fprintf(stderr, "CUDA error at %s:%d: %s\n", file, line, cudaGetErrorString(err));
    std::exit(EXIT_FAILURE);
  }
}
#define CUDA_CHECK(err) cuda_check((err), __FILE__, __LINE__)

void initialize_data(float* f) {
  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (i == 0 || i == N - 1) {
        f[IDX(i, j)] = sinf(j * 2.0f * static_cast<float>(M_PI) / (N - 1));
      } else if (j == 0 || j == N - 1) {
        f[IDX(i, j)] = sinf(i * 2.0f * static_cast<float>(M_PI) / (N - 1));
      } else {
        f[IDX(i, j)] = 0.0f;
      }
    }
  }
}

__global__ void jacobi_reduce_kernel(const float* f_old, float* f, float* partials) {
  __shared__ float sdata[16 * 16];

  const int tx = threadIdx.x;
  const int ty = threadIdx.y;
  const int tid = ty * blockDim.x + tx;

  const int i = blockIdx.x * blockDim.x + tx + 1;
  const int j = blockIdx.y * blockDim.y + ty + 1;

  float err = 0.0f;

  if (i <= N - 2 && j <= N - 2) {
    const float t = 0.25f * (f_old[IDX(i - 1, j)] +
                             f_old[IDX(i + 1, j)] +
                             f_old[IDX(i, j - 1)] +
                             f_old[IDX(i, j + 1)]);
    const float df = t - f_old[IDX(i, j)];
    f[IDX(i, j)] = t;
    err = df * df;
  }

  sdata[tid] = err;
  __syncthreads();

  for (int stride = (blockDim.x * blockDim.y) / 2; stride > 0; stride >>= 1) {
    if (tid < stride) {
      sdata[tid] += sdata[tid + stride];
    }
    __syncthreads();
  }

  if (tid == 0) {
    partials[blockIdx.y * gridDim.x + blockIdx.x] = sdata[0];
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  float* f = static_cast<float*>(std::malloc(N * N * sizeof(float)));
  float* f_old = static_cast<float*>(std::malloc(N * N * sizeof(float)));

  float error = std::numeric_limits<float>::max();
  const float tolerance = 1.e-5f;

  initialize_data(f);
  initialize_data(f_old);

  const int max_iters = 10000;
  int num_iters = 0;

  float* d_f = nullptr;
  float* d_f_old = nullptr;
  float* d_partials = nullptr;

  CUDA_CHECK(cudaMalloc(&d_f, N * N * sizeof(float)));
  CUDA_CHECK(cudaMalloc(&d_f_old, N * N * sizeof(float)));

  CUDA_CHECK(cudaMemcpy(d_f, f, N * N * sizeof(float), cudaMemcpyHostToDevice));
  CUDA_CHECK(cudaMemcpy(d_f_old, f_old, N * N * sizeof(float), cudaMemcpyHostToDevice));

  dim3 block(16, 16);
  dim3 grid((N - 2 + block.x - 1) / block.x, (N - 2 + block.y - 1) / block.y);
  const int num_blocks = grid.x * grid.y;

  CUDA_CHECK(cudaMalloc(&d_partials, num_blocks * sizeof(float)));
  std::vector<float> h_partials(num_blocks);

  {
    auto start = std::chrono::steady_clock::now();

    while (error > tolerance && num_iters < max_iters) {
      jacobi_reduce_kernel<<<grid, block>>>(d_f_old, d_f, d_partials);
      CUDA_CHECK(cudaGetLastError());

      CUDA_CHECK(cudaMemcpy(h_partials.data(), d_partials, num_blocks * sizeof(float), cudaMemcpyDeviceToHost));

      error = 0.0f;
      for (int i = 0; i < num_blocks; ++i) {
        error += h_partials[i];
      }

      error = sqrtf(error / (N * N));

      if (num_iters % 1000 == 0) {
        std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
      }

      float* tmp = d_f_old;
      d_f_old = d_f;
      d_f = tmp;

      ++num_iters;
    }

    CUDA_CHECK(cudaDeviceSynchronize());

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";
  }

  if (error <= tolerance && num_iters < max_iters) {
    std::cout << "PASS" << std::endl;
  } else {
    std::cout << "FAIL" << std::endl;
    cudaFree(d_partials);
    cudaFree(d_f);
    cudaFree(d_f_old);
    std::free(f);
    std::free(f_old);
    return -1;
  }

  CUDA_CHECK(cudaFree(d_partials));
  CUDA_CHECK(cudaFree(d_f));
  CUDA_CHECK(cudaFree(d_f_old));

  std::free(f);
  std::free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}

