static void initialize_data(float* f) {
  const float pi = acosf(-1.0f);
  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (i == 0 || i == N - 1) {
        f[IDX(i, j)] = sinf(j * 2.0f * pi / (N - 1));
      } else if (j == 0 || j == N - 1) {
        f[IDX(i, j)] = sinf(i * 2.0f * pi / (N - 1));
      } else {
        f[IDX(i, j)] = 0.0f;
      }
    }
  }
}

__global__ void jacobi_step_reduce(const float* __restrict__ f_old,
                                   float* __restrict__ f,
                                   float* __restrict__ error) {
  __shared__ float sdata[256];

  const int tid = threadIdx.x;
  const int interior = N - 2;
  const int total = interior * interior;
  const int stride = blockDim.x * gridDim.x;
  int idx = blockIdx.x * blockDim.x + tid;

  float local_sum = 0.0f;

  while (idx < total) {
    const int i = (idx % interior) + 1;
    const int j = (idx / interior) + 1;
    const int center = IDX(i, j);

    float t = 0.25f * (f_old[center - 1] +
                       f_old[center + 1] +
                       f_old[center - N] +
                       f_old[center + N]);
    float df = t - f_old[center];
    f[center] = t;
    local_sum += df * df;

    idx += stride;
  }

  sdata[tid] = local_sum;
  __syncthreads();

  for (int offset = blockDim.x / 2; offset > 0; offset >>= 1) {
    if (tid < offset) {
      sdata[tid] += sdata[tid + offset];
    }
    __syncthreads();
  }

  if (tid == 0) {
    atomicAdd(error, sdata[0]);
  }
}

int main() {
