#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <chrono>
#include <cuda_runtime.h>

#define _QUEENS_BLOCK_SIZE_   128
#define _EMPTY_      -1

typedef struct queen_root{
  unsigned int control;
  int8_t board[12];
} QueenRoot;

static inline void cudaCheck(cudaError_t err)
{
  if (err != cudaSuccess) {
    exit(1);
  }
}

inline void prefixesHandleSol(QueenRoot *root_prefixes, unsigned int flag,
                              const char *board, int initialDepth, int num_sol)
{
  root_prefixes[num_sol].control = flag;
  for(int i = 0; i < initialDepth; ++i)
    root_prefixes[num_sol].board[i] = board[i];
}

inline bool MCstillLegal(const char *board, const int r)
{
  for (int i = 0; i < r; ++i)
    if (board[i] == board[r]) return false;

  int ld = board[r];
  int rd = board[r];
  for (int i = r - 1; i >= 0; --i) {
    --ld; ++rd;
    if (board[i] == ld || board[i] == rd) return false;
  }
  return true;
}

__device__ bool queens_stillLegal(const char *board, const int r)
{
  bool safe = true;

  for (int i = 0; i < r; ++i)
    if (board[i] == board[r]) safe = false;

  int ld = board[r];
  int rd = board[r];
  for (int i = r - 1; i >= 0; --i) {
    --ld; ++rd;
    if (board[i] == ld || board[i] == rd) safe = false;
  }
  return safe;
}

__global__ void BP_queens_root_dfs_kernel(
  int N, unsigned int nPreFixos, int depthPreFixos,
  const QueenRoot *__restrict__ root_prefixes,
  unsigned long long *__restrict__ vector_of_tree_size,
  unsigned long long *__restrict__ sols)
{
  unsigned int idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (idx >= nPreFixos) return;

  unsigned int flag = 0;
  unsigned int bit_test = 0;
  char vertice[20];
  int N_l = N;
  int i, depth;
  unsigned long long qtd_solutions_thread = 0ULL;
  int depthGlobal = depthPreFixos;
  unsigned long long tree_size = 0ULL;

#pragma unroll 2
  for (i = 0; i < N_l; ++i) {
    vertice[i] = _EMPTY_;
  }

  flag = root_prefixes[idx].control;

#pragma unroll 2
  for (i = 0; i < depthGlobal; ++i)
    vertice[i] = (char)root_prefixes[idx].board[i];

  depth = depthGlobal;

  do {
    vertice[depth]++;
    bit_test = 0;
    bit_test |= (1u << vertice[depth]);
    if (vertice[depth] == N_l) {
      vertice[depth] = _EMPTY_;
    } else if (!(flag & bit_test) && queens_stillLegal(vertice, depth)) {
      ++tree_size;
      flag |= (1ULL << vertice[depth]);
      depth++;
      if (depth == N_l) {
        ++qtd_solutions_thread;
      } else continue;
    } else continue;
    depth--;
    flag &= ~(1ULL << vertice[depth]);
  } while (depth >= depthGlobal);

  sols[idx] = qtd_solutions_thread;
  vector_of_tree_size[idx] = tree_size;
}

void BP_queens_root_dfs(
  int N, unsigned int nPreFixos, int depthPreFixos,
  const QueenRoot *__restrict__ root_prefixes,
  unsigned long long *__restrict__ vector_of_tree_size,
  unsigned long long *__restrict__ sols)
{
  unsigned int threads = _QUEENS_BLOCK_SIZE_;
  unsigned int blocks = (nPreFixos + threads - 1) / threads;
  BP_queens_root_dfs_kernel<<<blocks, threads>>>(
    N, nPreFixos, depthPreFixos, root_prefixes, vector_of_tree_size, sols);
}

unsigned long long BP_queens_prefixes(int size, int initialDepth,
                                      unsigned long long *tree_size,
                                      QueenRoot *root_prefixes)
{
  unsigned int flag = 0;
  int bit_test = 0;
  char vertice[20];
  int i, nivel;
  unsigned long long local_tree = 0ULL;
  unsigned long long num_sol = 0;

  for (i = 0; i < size; ++i) {
    vertice[i] = -1;
  }

  nivel = 0;

  do {
    vertice[nivel]++;
    bit_test = 0;
    bit_test |= (1 << vertice[nivel]);

    if (vertice[nivel] == size) {
      vertice[nivel] = _EMPTY_;
    } else if (MCstillLegal(vertice, nivel) && !(flag & bit_test)) {
      flag |= (1ULL << vertice[nivel]);
      nivel++;
      ++local_tree;
      if (nivel == initialDepth) {
        prefixesHandleSol(root_prefixes, flag, vertice, initialDepth, (int)num_sol);
        num_sol++;
      } else continue;
    } else continue;

    nivel--;
    flag &= ~(1ULL << vertice[nivel]);

  } while (nivel >= 0);

  *tree_size = local_tree;

  return num_sol;
}

void nqueens(short size, int initial_depth, unsigned int n_explorers, QueenRoot *root_prefixes_h,
             unsigned long long *vector_of_tree_size_h, unsigned long long *sols_h, const int repeat)
{
  printf("\n### Regular BP-DFS search. ###\n");

  QueenRoot *root_prefixes_d = nullptr;
  unsigned long long *vector_of_tree_size_d = nullptr;
  unsigned long long *sols_d = nullptr;

  cudaCheck(cudaMalloc((void**)&root_prefixes_d, sizeof(QueenRoot) * (size_t)n_explorers));
  cudaCheck(cudaMalloc((void**)&vector_of_tree_size_d, sizeof(unsigned long long) * (size_t)n_explorers));
  cudaCheck(cudaMalloc((void**)&sols_d, sizeof(unsigned long long) * (size_t)n_explorers));

  cudaCheck(cudaMemcpy(root_prefixes_d, root_prefixes_h,
                       sizeof(QueenRoot) * (size_t)n_explorers,
                       cudaMemcpyHostToDevice));

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    BP_queens_root_dfs(size,
                       n_explorers,
                       initial_depth,
                       root_prefixes_d,
                       vector_of_tree_size_d,
                       sols_d);
    cudaCheck(cudaDeviceSynchronize());
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);

  cudaCheck(cudaMemcpy(vector_of_tree_size_h, vector_of_tree_size_d,
                       sizeof(unsigned long long) * (size_t)n_explorers,
                       cudaMemcpyDeviceToHost));
  cudaCheck(cudaMemcpy(sols_h, sols_d,
                       sizeof(unsigned long long) * (size_t)n_explorers,
                       cudaMemcpyDeviceToHost));

  cudaFree(root_prefixes_d);
  cudaFree(vector_of_tree_size_d);
  cudaFree(sols_d);
}

int main(int argc, char *argv[])
{
  if (argc != 4) {
    printf("Usage: %s <size> <initial depth> <repeat>\n", argv[0]);
    return 1;
  }
  const short size = atoi(argv[1]);
  const int initialDepth = atoi(argv[2]);
  const int repeat = atoi(argv[3]);
  printf("\n### Initial depth: %d - Size: %d:", initialDepth, size);

  unsigned long long tree_size = 0ULL;
  unsigned long long qtd_sols_global = 0ULL;
  unsigned int nMaxPrefixos = 75580635;

  QueenRoot* root_prefixes_h = (QueenRoot*)malloc(sizeof(QueenRoot) * nMaxPrefixos);
