template <typename T, int BLOCK_SIZE>
__global__ void conv1d_kernel(const T* __restrict__ mask,
                              const T* __restrict__ in,
                              T* __restrict__ out,
                              const int input_width,
                              const int mask_width) {
  int i = blockIdx.x * BLOCK_SIZE + threadIdx.x;
  if (i < input_width) {
    int start = i - mask_width / 2;
    T s = 0;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += in[start + j] * mask[j];
      }
    }
    out[i] = s;
  }
}

template <typename T, int BLOCK_SIZE>
void conv1d(const T* __restrict__ mask,
            const T* __restrict__ in,
            T* __restrict__ out,
            const int input_width,
            const int mask_width) {
  int grid = input_width / BLOCK_SIZE;
  conv1d_kernel<T, BLOCK_SIZE><<<grid, BLOCK_SIZE>>>(mask, in, out, input_width, mask_width);
}

template <typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_kernel(const T* __restrict__ mask,
                                    const T* __restrict__ in,
                                    T* __restrict__ out,
                                    const int input_width,
                                    const int mask_width) {
  __shared__ T tile[BLOCK_SIZE + MAX_MASK_WIDTH - 1];

  int bid = blockIdx.x;
  int lid = threadIdx.x;
  int dim = BLOCK_SIZE;
  int i = bid * dim + lid;

  int n = mask_width / 2;

  int halo_left = (bid - 1) * dim + lid;
  if (lid >= dim - n) {
    tile[lid - (dim - n)] = halo_left < 0 ? (T)0 : in[halo_left];
  }

  tile[n + lid] = in[bid * dim + lid];

  int halo_right = (bid + 1) * dim + lid;
  if (lid < n) {
    tile[lid + dim + n] = halo_right >= input_width ? (T)0 : in[halo_right];
  }

  __syncthreads();

  T s = 0;
  for (int j = 0; j < mask_width; j++) {
    s += tile[lid + j] * mask[j];
  }

  out[i] = s;
}

template <typename T, int BLOCK_SIZE>
void conv1d_tiled(const T* __restrict__ mask,
                  const T* __restrict__ in,
                  T* __restrict__ out,
                  const int input_width,
                  const int mask_width) {
  int grid = input_width / BLOCK_SIZE;
  conv1d_tiled_kernel<T, BLOCK_SIZE><<<grid, BLOCK_SIZE>>>(mask, in, out, input_width, mask_width);
}

template <typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_caching_kernel(const T* __restrict__ mask,
                                            const T* __restrict__ in,
                                            T* __restrict__ out,
                                            const int input_width,
                                            const int mask_width) {
  __shared__ T tile[BLOCK_SIZE];

  int bid = blockIdx.x;
  int lid = threadIdx.x;
  int dim = BLOCK_SIZE;
  int i = bid * dim + lid;

  tile[lid] = in[i];
  __syncthreads();

  int this_tile_start = bid * dim;
  int next_tile_start = (bid + 1) * dim;
  int start = i - (mask_width / 2);
  T s = 0;
  for (int j = 0; j < mask_width; j++) {
    int in_index = start + j;
    if (in_index >= 0 && in_index < input_width) {
      if (in_index >= this_tile_start && in_index < next_tile_start) {
        s += tile[lid + j - (mask_width / 2)] * mask[j];
      } else {
        s += in[in_index] * mask[j];
      }
    }
  }
  out[i] = s;
}

template <typename T, int BLOCK_SIZE>
void conv1d_tiled_caching(const T* __restrict__ mask,
                          const T* __restrict__ in,
