bool within_epsilon(float* output, float* reference, const size_t dimx,
                    const size_t dimy, const unsigned int radius,
                    const float delta = 0.01f) {
  FILE* fp = std::fopen("./error_diff.txt", "w");
  if (!fp) fp = stderr;

  bool error = false;
  double norm2 = 0.0;

  for (size_t iy = 0; iy < dimy; iy++) {
    for (size_t ix = 0; ix < dimx; ix++) {
      if (ix >= radius && ix < (dimx - radius) && iy >= radius &&
          iy < (dimy - radius)) {
        float difference = std::fabs(*reference - *output);
        norm2 += difference * difference;
        if (difference > delta) {
          error = true;
          std::fprintf(fp, " ERROR: (%zu,%zu)\t%e instead of %e (|e|=%e)\n", ix, iy,
                       *output, *reference, difference);
        }
      }

      ++output;
      ++reference;
    }
  }

