  float max_diff, max_diff_ref;

  int i = 0;
  int n = 1000;
  int iter = max_iter;
  float thresh = threshold;
  int divisor = 2;

  int opt, opt_index = 0;
  while ((opt = getopt_long(argc, argv, "::n:i:t:q:", size_opts, &opt_index)) != -1) {
    switch (opt) {
    case 'n':
      n = atoi(optarg);
      break;
    case 'i':
      iter = atoi(optarg);
      break;
    case 't':
      thresh = atof(optarg);
      break;
    case 'q':
      divisor = atoi(optarg);
      break;
    default:
      usage(argv);
      exit(EXIT_FAILURE);
    }
  }

  size_t rank_size = (size_t)n * sizeof(float);
  size_t map_size = (size_t)n * (size_t)n * sizeof(float);
  size_t page_size = (size_t)n * (size_t)n * sizeof(int);
  size_t link_size = (size_t)n * sizeof(unsigned int);

  page_ranks = (float *)malloc(rank_size);
  maps = (float *)malloc(map_size);
  noutlinks = (unsigned int *)malloc(link_size);

  max_diff = max_diff_ref = 99.0f;

  for (i = 0; i < n; ++i) {
    noutlinks[i] = 0;
  }
  pages = random_pages(n, noutlinks, divisor);
  init_array(page_ranks, n, 1.0f / (float)n);

  float *diffs;
  diffs = (float *)malloc(rank_size);
  memset(diffs, 0, rank_size);

  size_t block_size = n < BLOCK_SIZE ? (size_t)n : (size_t)BLOCK_SIZE;
  if (block_size == 0) {
    block_size = 1;
  }
  int grid_size = (n + (int)block_size - 1) / (int)block_size;

  double ktime = 0.0;

  int *d_pages = NULL;
  float *d_maps = NULL;
  float *d_page_ranks = NULL;
  unsigned int *d_noutlinks = NULL;
  float *d_diffs = NULL;

  CHECK_CUDA(cudaMalloc((void **)&d_pages, page_size));
  CHECK_CUDA(cudaMalloc((void **)&d_page_ranks, rank_size));
  CHECK_CUDA(cudaMalloc((void **)&d_noutlinks, link_size));
  CHECK_CUDA(cudaMalloc((void **)&d_diffs, rank_size));
  CHECK_CUDA(cudaMalloc((void **)&d_maps, map_size));

  CHECK_CUDA(cudaMemcpy(d_pages, pages, page_size, cudaMemcpyHostToDevice));
  CHECK_CUDA(cudaMemcpy(d_page_ranks, page_ranks, rank_size, cudaMemcpyHostToDevice));
  CHECK_CUDA(cudaMemcpy(d_noutlinks, noutlinks, link_size, cudaMemcpyHostToDevice));
  CHECK_CUDA(cudaMemcpy(d_diffs, diffs, rank_size, cudaMemcpyHostToDevice));

  for (t = 1; t <= iter && max_diff >= thresh; ++t) {
    auto start = std::chrono::high_resolution_clock::now();

    map_kernel<<<grid_size, (int)block_size>>>(d_pages, d_page_ranks, d_maps, d_noutlinks, n);
    CHECK_CUDA(cudaGetLastError());

    reduce_kernel<<<grid_size, (int)block_size>>>(d_page_ranks, d_maps, n, d_diffs);
    CHECK_CUDA(cudaGetLastError());

    CHECK_CUDA(cudaDeviceSynchronize());

    auto end = std::chrono::high_resolution_clock::now();
    ktime += std::chrono::duration_cast<std::chrono::duration<double>>(end - start).count();

    CHECK_CUDA(cudaMemcpy(diffs, d_diffs, rank_size, cudaMemcpyDeviceToHost));
    max_diff = maximum_dif(diffs, n);
  }

  fprintf(stderr, "Max difference %f is reached at iteration %d\n", max_diff, t);
  printf("\"Options\": \"-n %d -i %d -t %f\". Total kernel execution time: %lf (s)\n",
         n, iter, thresh, ktime);

  CHECK_CUDA(cudaFree(d_pages));
  CHECK_CUDA(cudaFree(d_page_ranks));
  CHECK_CUDA(cudaFree(d_noutlinks));
  CHECK_CUDA(cudaFree(d_diffs));
  CHECK_CUDA(cudaFree(d_maps));

  memset(diffs, 0, rank_size);
  for (t = 1; t <= iter && max_diff_ref >= thresh; ++t) {
    map_ref(pages, page_ranks, maps, noutlinks, n);
    reduce_ref(page_ranks, maps, n, diffs);
    max_diff_ref = maximum_dif(diffs, n);
  }
  bool ok = fabsf(max_diff - max_diff_ref) < 1e-3f;
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(pages);
  free(maps);
  free(page_ranks);
  free(noutlinks);
  free(diffs);
  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <math.h>
#include <getopt.h>
#include <chrono>
#include <cuda_runtime.h>
#include "reference.h"

#define D_FACTOR (0.85f)
#ifndef BLOCK_SIZE
#define BLOCK_SIZE 256
#endif

const int max_iter = 1000;
const float threshold = 1e-16f;

#define CHECK_CUDA(call)                                                       \
  do {                                                                         \
    cudaError_t err__ = (call);                                                \
    if (err__ != cudaSuccess) {                                                \
      fprintf(stderr, "CUDA error at %s:%d: %s\n", __FILE__, __LINE__,         \
              cudaGetErrorString(err__));                                      \
      exit(EXIT_FAILURE);                                                      \
    }                                                                          \
  } while (0)

int *random_pages(int n, unsigned int *noutlinks, int divisor) {
  int i, j, k;
  int *pages = (int *)malloc((size_t)n * n * sizeof(int));

  if (divisor <= 0) {
    fprintf(stderr,
            "ERROR: Invalid divisor '%d' for random initialization, divisor should be greater or equal to 1\n",
            divisor);
    exit(1);
  }

  for (i = 0; i < n; ++i) {
    noutlinks[i] = 0;
    for (j = 0; j < n; ++j) {
      if (i != j && (abs(rand()) % divisor == 0)) {
        pages[(size_t)i * n + j] = 1;
        noutlinks[i] += 1;
      }
    }

    if (noutlinks[i] == 0) {
      do {
        k = abs(rand()) % n;
      } while (k == i);
      pages[(size_t)i * n + k] = 1;
      noutlinks[i] = 1;
    }
  }
  return pages;
}

void init_array(float *a, int n, float val) {
  int i;
  for (i = 0; i < n; ++i) {
    a[i] = val;
  }
}

void usage(char *argv[]) {
  fprintf(stderr,
          "Usage: %s [-n number of pages] [-i max iterations]"
          " [-t threshold] [-q divsor for zero density]\n",
          argv[0]);
}

static struct option size_opts[] = {
    {"number of pages", 1, NULL, 'n'},
    {"max number of iterations", 1, NULL, 'i'},
    {"minimum threshold", 1, NULL, 't'},
    {"divisor for zero density", 1, NULL, 'q'},
    {0, 0, 0, 0}};

float maximum_dif(float *difs, int n) {
  int i;
  float max = 0.0f;
  for (i = 0; i < n; ++i) {
    max = difs[i] > max ? difs[i] : max;
  }
  return max;
}

__global__ void map_kernel(const int *__restrict__ pages,
                           const float *__restrict__ page_ranks,
                           float *__restrict__ maps,
                           const unsigned int *__restrict__ noutlinks, int n) {
  int i = blockIdx.x * blockDim.x + threadIdx.x;
  if (i < n) {
    float outbound_rank = page_ranks[i] / (float)noutlinks[i];
    size_t base = (size_t)i * n;
    for (int j = 0; j < n; ++j) {
      maps[base + j] = pages[base + j] * outbound_rank;
    }
  }
}

__global__ void reduce_kernel(float *__restrict__ page_ranks,
                              const float *__restrict__ maps, int n,
                              float *__restrict__ diffs) {
  int j = blockIdx.x * blockDim.x + threadIdx.x;
  if (j < n) {
    float old_rank = page_ranks[j];
    float new_rank = 0.0f;
    for (int i = 0; i < n; ++i) {
      new_rank += maps[(size_t)i * n + j];
    }
    new_rank = ((1.f - D_FACTOR) / n) + (D_FACTOR * new_rank);
    diffs[j] = fmaxf(fabsf(new_rank - old_rank), diffs[j]);
    page_ranks[j] = new_rank;
  }
}

int main(int argc, char *argv[]) {
  int *pages;
  float *maps;
  float *page_ranks;
  unsigned int *noutlinks;
  int t;
  float max_diff, max_diff_ref;

  int i = 0;
  int n = 1000;
  int iter = max_iter;
  float thresh = threshold;
  int divisor = 2;

  int opt, opt_index = 0;
  while ((opt = getopt_long(argc, argv, "::n:i:t:q:", size_opts, &opt_index)) !=
         -1) {
    switch (opt) {
    case 'n':
      n = atoi(optarg);
      break;
    case 'i':
      iter = atoi(optarg);
      break;
    case 't':
      thresh = atof(optarg);
      break;
    case 'q':
      divisor = atoi(optarg);
      break;
    default:
      usage(argv);
      exit(EXIT_FAILURE);
    }
  }

  size_t rank_size = (size_t)n * sizeof(float);
  size_t map_size = (size_t)n * n * sizeof(float);
  size_t page_size = (size_t)n * n * sizeof(int);
  size_t link_size = (size_t)n * sizeof(unsigned int);

  page_ranks = (float *)malloc(rank_size);
  maps = (float *)malloc(map_size);
  noutlinks = (unsigned int *)malloc(link_size);

  max_diff = max_diff_ref = 99.0f;

  for (i = 0; i < n; ++i) {
    noutlinks[i] = 0;
  }
  pages = random_pages(n, noutlinks, divisor);
  init_array(page_ranks, n, 1.0f / (float)n);

  float *diffs;
  diffs = (float *)malloc(rank_size);
  memset(diffs, 0, rank_size);

  int block_size = n < BLOCK_SIZE ? n : BLOCK_SIZE;
  if (block_size <= 0)
    block_size = 1;
  int grid_size = (n + block_size - 1) / block_size;
  if (grid_size <= 0)
    grid_size = 1;

  double ktime = 0.0;

  int *d_pages = NULL;
  float *d_maps = NULL;
  float *d_page_ranks = NULL;
  unsigned int *d_noutlinks = NULL;
  float *d_diffs = NULL;

  CHECK_CUDA(cudaMalloc((void **)&d_pages, page_size));
  CHECK_CUDA(cudaMalloc((void **)&d_maps, map_size));
  CHECK_CUDA(cudaMalloc((void **)&d_page_ranks, rank_size));
  CHECK_CUDA(cudaMalloc((void **)&d_noutlinks, link_size));
  CHECK_CUDA(cudaMalloc((void **)&d_diffs, rank_size));

  CHECK_CUDA(cudaMemcpy(d_pages, pages, page_size, cudaMemcpyHostToDevice));
  CHECK_CUDA(
      cudaMemcpy(d_page_ranks, page_ranks, rank_size, cudaMemcpyHostToDevice));
  CHECK_CUDA(
      cudaMemcpy(d_noutlinks, noutlinks, link_size, cudaMemcpyHostToDevice));
  CHECK_CUDA(cudaMemcpy(d_diffs, diffs, rank_size, cudaMemcpyHostToDevice));

  cudaEvent_t start_evt, stop_evt;
  CHECK_CUDA(cudaEventCreate(&start_evt));
  CHECK_CUDA(cudaEventCreate(&stop_evt));

  for (t = 1; t <= iter && max_diff >= thresh; ++t) {
    CHECK_CUDA(cudaEventRecord(start_evt));
    map_kernel<<<grid_size, block_size>>>(d_pages, d_page_ranks, d_maps,
                                          d_noutlinks, n);
    reduce_kernel<<<grid_size, block_size>>>(d_page_ranks, d_maps, n, d_diffs);
    CHECK_CUDA(cudaEventRecord(stop_evt));
    CHECK_CUDA(cudaEventSynchronize(stop_evt));
    CHECK_CUDA(cudaGetLastError());

    float ms = 0.0f;
    CHECK_CUDA(cudaEventElapsedTime(&ms, start_evt, stop_evt));
    ktime += (double)ms / 1000.0;

    CHECK_CUDA(cudaMemcpy(diffs, d_diffs, rank_size, cudaMemcpyDeviceToHost));
    max_diff = maximum_dif(diffs, n);
  }

  fprintf(stderr, "Max difference %f is reached at iteration %d\n", max_diff,
          t);
  printf("\"Options\": \"-n %d -i %d -t %f\". Total kernel execution time: %lf (s)\n",
         n, iter, thresh, ktime);

  memset(diffs, 0, rank_size);
  for (t = 1; t <= iter && max_diff_ref >= thresh; ++t) {
    map_ref(pages, page_ranks, maps, noutlinks, n);
    reduce_ref(page_ranks, maps, n, diffs);
    max_diff_ref = maximum_dif(diffs, n);
  }
  bool ok = fabsf(max_diff - max_diff_ref) < 1e-3f;
  printf("%s\n", ok ? "PASS" : "FAIL");

  CHECK_CUDA(cudaEventDestroy(start_evt));
  CHECK_CUDA(cudaEventDestroy(stop_evt));
  CHECK_CUDA(cudaFree(d_pages));
  CHECK_CUDA(cudaFree(d_maps));
  CHECK_CUDA(cudaFree(d_page_ranks));
  CHECK_CUDA(cudaFree(d_noutlinks));
  CHECK_CUDA(cudaFree(d_diffs));

  free(pages);
  free(maps);
  free(page_ranks);
  free(noutlinks);
  free(diffs);
  return 0;
}
